div.script:
// 
(async function() {
  const gameUrl = "https://cdn.jsdelivr.net/gh/rainS-IM/BPLGames@main/BPLPremium.html";
  const baseUrl = "https://cdn.jsdelivr.net/gh/rainS-IM/BPLGames@main/";
  const status = document.getElementById('status');

  try {
    // 1. Fetch the raw text of your HTML
    const response = await fetch(gameUrl);
    if (!response.ok) throw new Error("Check your internet connection.");
    const htmlContent = await response.text();

    // 2. Create a clean iframe
    const iframe = document.createElement('iframe');
    iframe.style = "position:fixed; top:0; left:0; width:100%; height:100%; border:none; background:white;";

    // 3. Clear the SVG and insert the iframe
    document.body.innerHTML = "";
    document.body.appendChild(iframe);

    // 4. Inject the content + a <base> tag so relative links work
    const doc = iframe.contentWindow.document;
    doc.open();
    // The base tag tells Safari where to find your other files
    doc.write(`<base href="${baseUrl}">` + htmlContent);
    doc.close();
  } catch (err) {
    status.innerHTML = `<div style="color:red;">Error: ${err.message}</div>`;
  }
})();
//
